import json
from typing import List

def invalid_columns(board: str) -> List[int]:
    # board: multiline string with 9 lines of 9 digits (no spaces)
    rows = [line.strip() for line in board.splitlines() if line.strip()]
    if len(rows) != 9:
        raise ValueError(f"Expected 9 rows, got {len(rows)}")
    for r in rows:
        if len(r) != 9 or not all(ch.isdigit() for ch in r):
            raise ValueError("Each row must be exactly 9 digits")
    invalid = []
    required = set("123456789")
    for c in range(9):
        col = "".join(rows[r][c] for r in range(9))
        if set(col) != required:
            invalid.append(c+1)  # 1-based index
    return invalid

# Read board from CONTEXT after 'BOARD:' line
lines = CONTEXT.lines(0, CONTEXT.line_count())
