try:
    board_start = next(i for i, ln in enumerate(lines) if ln.strip().startswith("BOARD"))
except StopIteration:
    raise RuntimeError("No BOARD: marker found in CONTEXT")
board_lines = lines[board_start+1:board_start+1+9]
board_text = "\n".join(line.strip() for line in board_lines)

invalid_cols = invalid_columns(board_text)

if not invalid_cols:
    done("VALID")
else:
    done(json.dumps({"invalid_cols": invalid_cols}))
